"use client";

import { type RemocnTheme, useRemocnTheme } from "@/lib/remocn-ui";

export type CursorVariant = "arrow" | "pointer";

export interface CursorStyle {
  x: number;
  y: number;
  scale: number;
  rippleOpacity: number;
  rippleScale: number;
  pressScale?: number;
}

export interface CursorProps {
  style?: CursorStyle;
  variant?: CursorVariant;
  size?: number;
  theme?: Partial<RemocnTheme>;
  mode?: "light" | "dark";
  rippleColor?: string;
  className?: string;
}

const REST: CursorStyle = {
  x: 0,
  y: 0,
  scale: 1,
  rippleOpacity: 0,
  rippleScale: 0,
};

const ARROW_PATH =
  "M1 1 L1 18.5 L5.6 14.4 L8.7 21.6 L11.6 20.4 L8.5 13.2 L14.5 13.2 Z";
const POINTER_PATH =
  "M8 2.2 C8 1.3 8.7 0.7 9.5 0.7 C10.3 0.7 11 1.3 11 2.2 L11 9 " +
  "C11 9 11.3 8.4 12.2 8.4 C13 8.4 13.4 9 13.4 9.6 " +
  "C13.4 9.6 13.9 9.1 14.7 9.1 C15.5 9.1 15.9 9.7 15.9 10.3 " +
  "C15.9 10.3 16.4 9.9 17.1 9.9 C17.9 9.9 18.3 10.5 18.3 11.2 " +
  "L18.3 16.8 C18.3 19.8 16.3 22.3 12.8 22.3 L11.4 22.3 " +
  "C9 22.3 7.9 21.2 6.6 19.2 L4 15.2 C3.5 14.4 3.7 13.4 4.5 12.9 " +
  "C5.1 12.5 5.9 12.6 6.4 13.2 L8 15 Z";

export function Cursor({
  style,
  variant = "arrow",
  size = 28,
  theme: themeOverride,
  mode,
  rippleColor,
  className,
}: CursorProps) {
  const theme = useRemocnTheme(themeOverride, mode);
  const v = style ?? REST;

  const press = v.pressScale ?? 1;
  const pressedScale = v.scale * (0.9 + 0.1 * press);

  const ring = rippleColor ?? theme.primary;
  const fill = theme.foreground;
  const stroke = theme.background;
  const rippleSize = size * 1.8;

  return (
    <div
      className={className}
      style={{
        position: "absolute",
        left: 0,
        top: 0,
        transform: `translate(${v.x}px, ${v.y}px)`,
        pointerEvents: "none",
      }}
    >
      {}
      <div
        style={{
          position: "absolute",
          left: -rippleSize / 2,
          top: -rippleSize / 2,
          width: rippleSize,
          height: rippleSize,
          borderRadius: "50%",
          border: `2px solid ${ring}`,
          opacity: v.rippleOpacity,
          transform: `scale(${v.rippleScale})`,
          transformOrigin: "center",
        }}
      />
      {}
      <svg
        width={size}
        height={size}
        viewBox="0 0 24 24"
        fill="none"
        style={{
          position: "absolute",
          left: 0,
          top: 0,
          transform: `scale(${pressedScale})`,
          transformOrigin: "0 0",
          filter: "drop-shadow(0 1px 2px rgba(0,0,0,0.3))",
          overflow: "visible",
        }}
      >
        <path
          d={variant === "pointer" ? POINTER_PATH : ARROW_PATH}
          fill={fill}
          stroke={stroke}
          strokeWidth={1.4}
          strokeLinejoin="round"
        />
      </svg>
    </div>
  );
}

"use client";

import type { CSSProperties, ReactNode } from "react";
import { type RemocnTheme, useRemocnTheme } from "@/lib/remocn-ui";

export interface FieldGroupProps {
  children: ReactNode;
  gap?: number;
  style?: CSSProperties;
}

export function FieldGroup({ children, gap = 16, style }: FieldGroupProps) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap, ...style }}>
      {children}
    </div>
  );
}

export interface FieldProps {
  children: ReactNode;
  gap?: number;
  style?: CSSProperties;
}

export function Field({ children, gap = 6, style }: FieldProps) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap, ...style }}>
      {children}
    </div>
  );
}

export interface FieldLabelProps {
  children: ReactNode;
  mode?: "light" | "dark";
  theme?: Partial<RemocnTheme>;
  style?: CSSProperties;
}

export function FieldLabel({ children, mode, theme, style }: FieldLabelProps) {
  const t = useRemocnTheme(theme, mode);
  return (
    <div
      style={{
        fontSize: 13,
        lineHeight: "18px",
        fontWeight: 500,
        letterSpacing: "-0.01em",
        color: t.foreground,
        ...style,
      }}
    >
      {children}
    </div>
  );
}

export interface FieldDescriptionProps {
  children: ReactNode;
  align?: "start" | "center";
  mode?: "light" | "dark";
  theme?: Partial<RemocnTheme>;
  style?: CSSProperties;
}

export function FieldDescription({
  children,
  align = "start",
  mode,
  theme,
  style,
}: FieldDescriptionProps) {
  const t = useRemocnTheme(theme, mode);
  return (
    <div
      style={{
        fontSize: 12,
        lineHeight: "16px",
        color: t.mutedForeground,
        textAlign: align === "center" ? "center" : "left",
        ...style,
      }}
    >
      {children}
    </div>
  );
}

export interface FieldControlProps {
  children: ReactNode;
  height?: number;
  style?: CSSProperties;
}

export function FieldControl({ children, height = 40, style }: FieldControlProps) {
  return (
    <div style={{ position: "relative", height, ...style }}>{children}</div>
  );
}

"use client";

import { mixOklch, type RemocnTheme, useRemocnTheme } from "@/lib/remocn-ui";

export type InputState =
  | "idle"
  | "hover"
  | "active"
  | "typing"
  | "blur"
  | "invalid";

type InputSize = "sm" | "default" | "lg";

export interface InputProps {
  state?: InputState;
  style?: InputStyle;
  placeholder?: string;
  value?: string;
  size?: InputSize;
  theme?: Partial<RemocnTheme>;
  primary?: string;
  mode?: "light" | "dark";
  fullWidth?: boolean;
  className?: string;
}

const FIELD_WIDTH = 320;

const SIZE_STYLES: Record<
  InputSize,
  { height: number; padding: number; fontSize: number }
> = {
  sm: { height: 36, padding: 12, fontSize: 13 },
  default: { height: 40, padding: 14, fontSize: 15 },
  lg: { height: 48, padding: 16, fontSize: 17 },
};

export interface InputStyle {
  borderColor: string;
  ringColor: string;
  ringWidth: number;
  background: string;
  caretOpacity: number;
  valueReveal: number;
  placeholderOpacity: number;
}

export interface InputStyleContext {
  idleBorder: string;
  hoverBorder: string;
  activeBorder: string;
  invalidBorder: string;
  ring: string;
  invalidRing: string;
  background: string;
  hoverBackground: string;
  foreground: string;
  mutedForeground: string;
}

export function inputStyleContext(theme: RemocnTheme): InputStyleContext {
  return {
    idleBorder: theme.input,
    hoverBorder: mixOklch(theme.input, theme.foreground, 0.18),
    activeBorder: theme.ring,
    invalidBorder: theme.destructive,
    ring: mixOklch(theme.background, theme.ring, 0.5),
    invalidRing: mixOklch(theme.background, theme.destructive, 0.4),
    background: theme.background,
    hoverBackground: mixOklch(theme.background, theme.muted, 0.4),
    foreground: theme.foreground,
    mutedForeground: theme.mutedForeground,
  };
}

export function inputStyle(
  state: InputState,
  ctx: InputStyleContext,
): InputStyle {
  switch (state) {
    case "hover":
      return {
        borderColor: ctx.hoverBorder,
        ringColor: ctx.ring,
        ringWidth: 0,
        background: ctx.hoverBackground,
        caretOpacity: 0,
        valueReveal: 0,
        placeholderOpacity: 1,
      };
    case "active":
      return {
        borderColor: ctx.activeBorder,
        ringColor: ctx.ring,
        ringWidth: 3,
        background: ctx.background,
        caretOpacity: 1,
        valueReveal: 0,
        placeholderOpacity: 1,
      };
    case "typing":
      return {
        borderColor: ctx.activeBorder,
        ringColor: ctx.ring,
        ringWidth: 3,
        background: ctx.background,
        caretOpacity: 1,
        valueReveal: 1,
        placeholderOpacity: 0,
      };
    case "blur":
      return {
        borderColor: ctx.idleBorder,
        ringColor: ctx.ring,
        ringWidth: 0,
        background: ctx.background,
        caretOpacity: 0,
        valueReveal: 1,
        placeholderOpacity: 0,
      };
    case "invalid":
      return {
        borderColor: ctx.invalidBorder,
        ringColor: ctx.invalidRing,
        ringWidth: 3,
        background: ctx.background,
        caretOpacity: 0,
        valueReveal: 1,
        placeholderOpacity: 0,
      };
    default:
      return {
        borderColor: ctx.idleBorder,
        ringColor: ctx.ring,
        ringWidth: 0,
        background: ctx.background,
        caretOpacity: 0,
        valueReveal: 0,
        placeholderOpacity: 1,
      };
  }
}

export function Input({
  state = "idle",
  style,
  placeholder = "you@example.com",
  value = "remotion@remocn.dev",
  size = "default",
  theme: themeOverride,
  primary,
  mode,
  fullWidth = false,
  className,
}: InputProps) {
  const theme = useRemocnTheme(
    { ...themeOverride, ...(primary ? { primary } : {}) },
    mode,
  );

  const sizeStyle = SIZE_STYLES[size];
  const ctx = inputStyleContext(theme);
  const v = style ?? inputStyle(state, ctx);
  const revealed = value.slice(0, Math.round(value.length * v.valueReveal));

  return (
    <div
      style={{
        position: "absolute",
        inset: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: theme.background,
        fontFamily:
          "var(--font-geist-sans), -apple-system, BlinkMacSystemFont, sans-serif",
      }}
    >
      <div
        className={className}
        style={{
          position: "relative",
          display: "flex",
          alignItems: "center",
          width: fullWidth ? "100%" : FIELD_WIDTH,
          height: sizeStyle.height,
          padding: `0 ${sizeStyle.padding}px`,
          fontSize: sizeStyle.fontSize,
          letterSpacing: "-0.01em",
          background: v.background,
          border: `1px solid ${v.borderColor}`,
          borderRadius: theme.radius,
          boxShadow: `0 0 0 ${v.ringWidth}px ${v.ringColor}`,
        }}
      >
        {}
        <span
          style={{
            position: "absolute",
            left: sizeStyle.padding,
            color: ctx.mutedForeground,
            opacity: v.valueReveal > 0 ? 0 : v.placeholderOpacity,
            pointerEvents: "none",
            whiteSpace: "nowrap",
          }}
        >
          {placeholder}
        </span>
        {}
        <div style={{ display: "flex", alignItems: "center", minWidth: 0 }}>
          <span style={{ whiteSpace: "nowrap", color: ctx.foreground }}>
            {revealed}
          </span>
          <span
            style={{
              flexShrink: 0,
              width: 2,
              height: Math.round(sizeStyle.fontSize * 1.1),
              borderRadius: 1,
              background: ctx.foreground,
              opacity: v.caretOpacity,
              marginLeft: revealed.length > 0 ? 4 : 0,
            }}
          />
        </div>
      </div>
    </div>
  );
}

"use client";

import { type RemocnTheme, useRemocnTheme } from "@/lib/remocn-ui";
import { Cursor } from "@/components/remocn/cursor";
import { useCursorPath } from "@/components/remocn/use-cursor-path";
import { Input } from "@/components/remocn/input";
import { useInputTransition } from "@/components/remocn/use-input-transition";
import { Button } from "@/components/remocn/button";
import { useButtonTransition } from "@/components/remocn/use-button-transition";
import { Toast } from "@/components/remocn/toast";
import { useToastTransition } from "@/components/remocn/use-toast-transition";
import { BlurIn } from "@/components/remocn/blur-in";
import { useBlurInTransition } from "@/components/remocn/use-blur-in-transition";
import {
  Field,
  FieldControl,
  FieldDescription,
  FieldGroup,
  FieldLabel,
} from "@/components/remocn/field";

export interface SignupFlowProps {
  title?: string;
  description?: string;
  fullName?: string;
  email?: string;
  password?: string;
  createLabel?: string;
  googleLabel?: string;
  signinText?: string;
  toastTitle?: string;
  mode?: "light" | "dark";
  theme?: Partial<RemocnTheme>;
}

const STAGE_W = 1280;
const CARD_W = 376;
const CARD_TOP = 48;
const CARD_LEFT = (STAGE_W - CARD_W) / 2;
const CENTER_X = STAGE_W / 2;

const NAME_Y = 216;
const EMAIL_Y = 296;
const PASS_Y = 398;
const CONFIRM_Y = 500;
const CREATE_Y = 564;

export function SignupFlow({
  title = "Create an account",
  description = "Enter your information below to create your account",
  fullName = "John Doe",
  email = "m@example.com",
  password = "••••••••",
  createLabel = "Create account",
  toastTitle = "Account created",
  mode = "light",
  theme,
}: SignupFlowProps) {
  const resolved = useRemocnTheme(theme, mode);
  const opts = { mode, theme };

  const cardEnter = useBlurInTransition(
    [{ at: 0, state: "revealed", duration: 18 }],
    { distance: 0 },
  );
  const enterHeader = useBlurInTransition([
    { at: 18, state: "revealed", duration: 16 },
  ]);
  const enterName = useBlurInTransition([
    { at: 24, state: "revealed", duration: 16 },
  ]);
  const enterEmail = useBlurInTransition([
    { at: 30, state: "revealed", duration: 16 },
  ]);
  const enterPass = useBlurInTransition([
    { at: 36, state: "revealed", duration: 16 },
  ]);
  const enterConfirm = useBlurInTransition([
    { at: 42, state: "revealed", duration: 16 },
  ]);
  const enterButton = useBlurInTransition([
    { at: 48, state: "revealed", duration: 16 },
  ]);

  const DEMO = 48;

  const cursorStyle = useCursorPath([
    { at: 0, x: 160, y: 120 },
    { at: 18 + DEMO, x: CENTER_X, y: NAME_Y, duration: 18, click: true },
    { at: 52 + DEMO, x: CENTER_X, y: EMAIL_Y, duration: 30, click: true },
    { at: 96 + DEMO, x: CENTER_X, y: PASS_Y, duration: 40, click: true },
    { at: 134 + DEMO, x: CENTER_X, y: CONFIRM_Y, duration: 32, click: true },
    { at: 176 + DEMO, x: CENTER_X, y: CREATE_Y, duration: 38, click: true },
  ]);

  const nameStyle = useInputTransition(
    [
      { at: 18 + DEMO, state: "active", duration: 6 },
      { at: 20 + DEMO, state: "typing", duration: 20 },
      { at: 52 + DEMO, state: "blur", duration: 8 },
    ],
    opts,
  );
  const emailStyle = useInputTransition(
    [
      { at: 52 + DEMO, state: "active", duration: 6 },
      { at: 54 + DEMO, state: "typing", duration: 28 },
      { at: 96 + DEMO, state: "blur", duration: 8 },
    ],
    opts,
  );
  const passStyle = useInputTransition(
    [
      { at: 96 + DEMO, state: "active", duration: 6 },
      { at: 98 + DEMO, state: "typing", duration: 22 },
      { at: 134 + DEMO, state: "blur", duration: 8 },
    ],
    opts,
  );
  const confirmStyle = useInputTransition(
    [
      { at: 134 + DEMO, state: "active", duration: 6 },
      { at: 136 + DEMO, state: "typing", duration: 22 },
      { at: 176 + DEMO, state: "blur", duration: 8 },
    ],
    opts,
  );

  const buttonStyle = useButtonTransition(
    [
      { at: 176 + DEMO, state: "hover", duration: 8 },
      { at: 186 + DEMO, state: "press", duration: 6 },
      { at: 192 + DEMO, state: "loading", duration: 6 },
      { at: 234 + DEMO, state: "success", duration: 16 },
    ],
    opts,
  );

  const toastStyle = useToastTransition(
    [
      { at: 234 + DEMO, state: "visible", duration: 14 },
      { at: 300 + DEMO, state: "hidden", duration: 14 },
    ],
    { mode },
  );

  return (
    <div
      style={{
        position: "relative",
        width: "100%",
        height: "100%",
        background: resolved.muted,
        fontFamily:
          "var(--font-geist-sans), -apple-system, BlinkMacSystemFont, sans-serif",
      }}
    >
      <div
        style={{
          position: "absolute",
          left: CARD_LEFT,
          top: CARD_TOP,
          width: CARD_W,
          height: 580,
          boxSizing: "border-box",
          padding: 28,
          display: "flex",
          flexDirection: "column",
          gap: 24,
          background: resolved.background,
          border: `1px solid ${resolved.border}`,
          borderRadius: 14,
          boxShadow:
            "0 10px 30px -12px rgba(0,0,0,0.22), 0 2px 8px -3px rgba(0,0,0,0.10)",
          opacity: cardEnter.opacity,
          filter: cardEnter.blur > 0 ? `blur(${cardEnter.blur}px)` : "none",
        }}
      >
        <BlurIn display="block" style={enterHeader}>
          <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
            <div
              style={{
                fontSize: 22,
                lineHeight: "28px",
                fontWeight: 600,
                letterSpacing: "-0.02em",
                color: resolved.cardForeground,
              }}
            >
              {title}
            </div>
            <div
              style={{
                fontSize: 14,
                lineHeight: "20px",
                color: resolved.mutedForeground,
              }}
            >
              {description}
            </div>
          </div>
        </BlurIn>

        <FieldGroup gap={16}>
          <BlurIn display="block" style={enterName}>
            <Field>
              <FieldLabel mode={mode} theme={theme}>
                Full Name
              </FieldLabel>
              <FieldControl>
                <Input
                  placeholder={fullName}
                  value={fullName}
                  style={nameStyle}
                  mode={mode}
                  theme={theme}
                />
              </FieldControl>
            </Field>
          </BlurIn>

          <BlurIn display="block" style={enterEmail}>
            <Field>
              <FieldLabel mode={mode} theme={theme}>
                Email
              </FieldLabel>
              <FieldControl>
                <Input
                  placeholder={email}
                  value={email}
                  style={emailStyle}
                  mode={mode}
                  theme={theme}
                />
              </FieldControl>
              <FieldDescription mode={mode} theme={theme}>
                We'll use this to contact you.
              </FieldDescription>
            </Field>
          </BlurIn>

          <BlurIn display="block" style={enterPass}>
            <Field>
              <FieldLabel mode={mode} theme={theme}>
                Password
              </FieldLabel>
              <FieldControl>
                <Input
                  placeholder={password}
                  value={password}
                  style={passStyle}
                  mode={mode}
                  theme={theme}
                />
              </FieldControl>
              <FieldDescription mode={mode} theme={theme}>
                Must be at least 8 characters long.
              </FieldDescription>
            </Field>
          </BlurIn>

          <BlurIn display="block" style={enterConfirm}>
            <Field>
              <FieldLabel mode={mode} theme={theme}>
                Confirm Password
              </FieldLabel>
              <FieldControl>
                <Input
                  placeholder={password}
                  value={password}
                  style={confirmStyle}
                  mode={mode}
                  theme={theme}
                />
              </FieldControl>
            </Field>
          </BlurIn>
        </FieldGroup>

        <BlurIn display="block" style={enterButton}>
          <Field gap={10}>
            <FieldControl>
              <Button
                label={createLabel}
                style={buttonStyle}
                theme={theme}
              />
            </FieldControl>
          </Field>
        </BlurIn>
      </div>

      <div style={{ position: "absolute", right: 32, bottom: 32 }}>
        <Toast
          title={toastTitle}
          variant="success"
          style={toastStyle}
          mode={mode}
          theme={theme}
        />
      </div>

      <Cursor style={cursorStyle} variant="pointer" mode={mode} theme={theme} />
    </div>
  );
}

"use client";

import { type RemocnTheme, useRemocnTheme } from "@/lib/remocn-ui";

export type ToastState = "hidden" | "visible";

export type ToastVariant = "default" | "success" | "error";

export interface ToastProps {
  state?: ToastState;
  style?: ToastStyle;
  title: string;
  description?: string;
  variant?: ToastVariant;
  theme?: Partial<RemocnTheme>;
  mode?: "light" | "dark";
  className?: string;
}

const TOAST_WIDTH = 356;

export interface ToastStyle {
  opacity: number;
  translateY: number;
  scale: number;
}

export interface ToastStyleContext {
  iconColor: string;
}

export function toastStyleContext(
  variant: ToastVariant,
  theme: RemocnTheme,
): ToastStyleContext {
  if (variant === "success") return { iconColor: "oklch(0.6 0.17 150)" };
  if (variant === "error") return { iconColor: theme.destructive };
  return { iconColor: theme.mutedForeground };
}

export function toastStyle(state: ToastState): ToastStyle {
  switch (state) {
    case "visible":
      return { opacity: 1, translateY: 0, scale: 1 };
    default:
      return { opacity: 0, translateY: 16, scale: 0.97 };
  }
}

function ToastIcon({
  variant,
  color,
}: {
  variant: ToastVariant;
  color: string;
}) {
  if (variant === "success") {
    return (
      <svg width={18} height={18} viewBox="0 0 24 24" fill="none">
        <circle cx="12" cy="12" r="9" stroke={color} strokeWidth="2" />
        <path
          d="M8 12.5l2.6 2.6L16 9"
          stroke={color}
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
        />
      </svg>
    );
  }
  if (variant === "error") {
    return (
      <svg width={18} height={18} viewBox="0 0 24 24" fill="none">
        <circle cx="12" cy="12" r="9" stroke={color} strokeWidth="2" />
        <path
          d="M12 7.5v5"
          stroke={color}
          strokeWidth="2"
          strokeLinecap="round"
        />
        <circle cx="12" cy="16" r="1.1" fill={color} />
      </svg>
    );
  }
  return (
    <svg width={18} height={18} viewBox="0 0 24 24" fill="none">
      <circle cx="12" cy="12" r="9" stroke={color} strokeWidth="2" />
      <path d="M12 11v5" stroke={color} strokeWidth="2" strokeLinecap="round" />
      <circle cx="12" cy="8" r="1.1" fill={color} />
    </svg>
  );
}

export function Toast({
  state = "hidden",
  style,
  title,
  description,
  variant = "default",
  theme: themeOverride,
  mode,
  className,
}: ToastProps) {
  const theme = useRemocnTheme(themeOverride, mode);
  const ctx = toastStyleContext(variant, theme);
  const v = style ?? toastStyle(state);

  return (
    <div
      className={className}
      style={{
        display: "flex",

        alignItems: description ? "flex-start" : "center",
        gap: 12,
        width: TOAST_WIDTH,
        padding: "16px",
        background: theme.popover,
        color: theme.popoverForeground,
        border: `1px solid ${theme.border}`,
        borderRadius: theme.radius,
        boxShadow:
          "0 10px 15px -3px rgba(0,0,0,0.1), 0 4px 6px -4px rgba(0,0,0,0.1)",
        opacity: v.opacity,
        transform: `translateY(${v.translateY}px) scale(${v.scale})`,
        transformOrigin: "bottom center",
        fontFamily:
          "var(--font-geist-sans), -apple-system, BlinkMacSystemFont, sans-serif",
      }}
    >
      <span
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          marginTop: description ? 1 : 0,
        }}
      >
        <ToastIcon variant={variant} color={ctx.iconColor} />
      </span>
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          gap: 4,
          minWidth: 0,
        }}
      >
        <span
          style={{
            fontSize: 14,
            fontWeight: 500,
            lineHeight: 1.3,
            letterSpacing: "-0.01em",
          }}
        >
          {title}
        </span>
        {description !== undefined && (
          <span
            style={{
              fontSize: 13,
              lineHeight: 1.4,
              color: theme.mutedForeground,
            }}
          >
            {description}
          </span>
        )}
      </div>
    </div>
  );
}

"use client";

import { useCurrentFrame } from "remotion";
import {
  clamp01,
  type EasingName,
  easings,
} from "@/lib/remocn-ui";
import type { CursorStyle } from "@/components/remocn/cursor";

export interface CursorWaypoint {
  at: number;
  x: number;
  y: number;
  duration?: number;
  click?: boolean;
  press?: boolean;
  easing?: EasingName;
}

export const DEFAULT_DURATION = 24;

export const CLICK_FRAMES = 16;

export const PRESS_FRAMES = 8;

export interface CursorPathOptions {
  speed?: number;
  defaultDuration?: number;
}

function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

export function ripplePhase(framesSinceClick: number): {
  rippleOpacity: number;
  rippleScale: number;
} {
  if (framesSinceClick < 0 || framesSinceClick >= CLICK_FRAMES) {
    return { rippleOpacity: 0, rippleScale: 0 };
  }
  const p = clamp01(framesSinceClick / CLICK_FRAMES);
  return {
    rippleOpacity: 0.5 * (1 - p),
    rippleScale: 2.5 * easings.out(p),
  };
}

export function clickPress(framesSinceClick: number): number {
  if (framesSinceClick < 0 || framesSinceClick >= PRESS_FRAMES) return 1;
  const half = PRESS_FRAMES / 2;
  const p =
    framesSinceClick < half
      ? framesSinceClick / half
      : 1 - (framesSinceClick - half) / half;
  return 1 - clamp01(p);
}

export function useCursorPath(
  waypoints: CursorWaypoint[],
  opts: CursorPathOptions = {},
): CursorStyle {
  const { speed = 1 } = opts;
  const raw = useCurrentFrame() * speed;
  return cursorPathAt(waypoints, raw, opts);
}

export function cursorPathAt(
  waypoints: CursorWaypoint[],
  raw: number,
  opts: CursorPathOptions = {},
): CursorStyle {
  const { defaultDuration = DEFAULT_DURATION } = opts;

  if (waypoints.length === 0) {
    return { x: 0, y: 0, scale: 1, rippleOpacity: 0, rippleScale: 0 };
  }

  const first = waypoints[0];

  if (raw <= first.at) {
    return {
      x: first.x,
      y: first.y,
      scale: 1,
      rippleOpacity: 0,
      rippleScale: 0,
      pressScale: 1,
    };
  }

  let toIndex = waypoints.length - 1;
  for (let i = 1; i < waypoints.length; i++) {
    if (waypoints[i].at > raw) {
      toIndex = i;
      break;
    }
  }
  const pastLast = raw >= waypoints[waypoints.length - 1].at;
  const to = pastLast ? waypoints[waypoints.length - 1] : waypoints[toIndex];
  const from = pastLast
    ? waypoints[waypoints.length - 1]
    : waypoints[toIndex - 1];

  const dur = to.duration ?? defaultDuration;
  const ease = easings[to.easing ?? "inOut"];
  const start = to.at - dur;
  const t = pastLast || dur <= 0 ? 1 : ease(clamp01((raw - start) / dur));
  const x = lerp(from.x, to.x, t);
  const y = lerp(from.y, to.y, t);

  let lastClickAt = -Infinity;
  for (const wp of waypoints) {
    if (wp.click && wp.at <= raw && wp.at > lastClickAt) lastClickAt = wp.at;
  }
  const sinceClick = lastClickAt === -Infinity ? -1 : raw - lastClickAt;
  const ripple = ripplePhase(sinceClick);
  const clickDip = clickPress(sinceClick);

  const holdWp = pastLast ? waypoints[waypoints.length - 1] : from;
  const heldPress = holdWp.press ? 0 : 1;

  const pressScale = Math.min(clickDip, heldPress);

  return {
    x,
    y,
    scale: 1,
    rippleOpacity: ripple.rippleOpacity,
    rippleScale: ripple.rippleScale,
    pressScale,
  };
}

"use client";

import {
  easings,
  mixOklch,
  type RemocnTheme,
  type Step,
  useRemocnTheme,
  useStateTransition,
} from "@/lib/remocn-ui";
import {
  inputStyle,
  inputStyleContext,
  type InputState,
  type InputStyle,
} from "@/components/remocn/input";

export const DEFAULT_DURATION = 8;

export function tweenInputStyle(
  a: InputStyle,
  b: InputStyle,
  t: number,
): InputStyle {
  return {
    ringWidth: a.ringWidth + (b.ringWidth - a.ringWidth) * t,
    caretOpacity: a.caretOpacity + (b.caretOpacity - a.caretOpacity) * t,
    valueReveal: a.valueReveal + (b.valueReveal - a.valueReveal) * t,
    placeholderOpacity:
      a.placeholderOpacity + (b.placeholderOpacity - a.placeholderOpacity) * t,
    borderColor: mixOklch(a.borderColor, b.borderColor, t),
    ringColor: mixOklch(a.ringColor, b.ringColor, t),
    background: mixOklch(a.background, b.background, t),
  };
}

export interface InputTransitionOptions {
  theme?: Partial<RemocnTheme>;
  mode?: "light" | "dark";
  primary?: string;
  speed?: number;
  defaultDuration?: number;
}

export function useInputTransition(
  steps: Step<InputState>[],
  opts: InputTransitionOptions = {},
): InputStyle {
  const {
    theme: themeOverride,
    mode,
    primary,
    speed = 1,
    defaultDuration = DEFAULT_DURATION,
  } = opts;
  const theme = useRemocnTheme(
    { ...themeOverride, ...(primary ? { primary } : {}) },
    mode,
  );
  const ctx = inputStyleContext(theme);
  const { from, to, progress } = useStateTransition(
    steps,
    "idle",
    speed,
    defaultDuration,
  );
  const t = easings.out(progress);
  return tweenInputStyle(inputStyle(from, ctx), inputStyle(to, ctx), t);
}

"use client";

import {
  easings,
  type Step,
  useStateTransition,
} from "@/lib/remocn-ui";
import {
  toastStyle,
  type ToastState,
  type ToastStyle,
} from "@/components/remocn/toast";

export const DEFAULT_DURATION = 12;

export function tweenToastStyle(
  a: ToastStyle,
  b: ToastStyle,
  t: number,
): ToastStyle {
  return {
    opacity: a.opacity + (b.opacity - a.opacity) * t,
    translateY: a.translateY + (b.translateY - a.translateY) * t,
    scale: a.scale + (b.scale - a.scale) * t,
  };
}

export interface ToastTransitionOptions {
  mode?: "light" | "dark";
  speed?: number;
  defaultDuration?: number;
}

export function useToastTransition(
  steps: Step<ToastState>[],
  opts: ToastTransitionOptions = {},
): ToastStyle {
  const { speed = 1, defaultDuration = DEFAULT_DURATION } = opts;
  const { from, to, progress } = useStateTransition(
    steps,
    "hidden",
    speed,
    defaultDuration,
  );
  const t = easings.out(progress);
  return tweenToastStyle(toastStyle(from), toastStyle(to), t);
}

